import{_ as a,c as e,o as i,a4 as l}from"./chunks/framework.I1cCAST3.js";const m=JSON.parse('{"title":"移动端常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/faq/index.md","filePath":"docs/mobile/faq/index.md"}'),o={name:"docs/mobile/faq/index.md"},t=l('<h1 id="移动端常见问题" tabindex="-1">移动端常见问题 <a class="header-anchor" href="#移动端常见问题" aria-label="Permalink to &quot;移动端常见问题&quot;">​</a></h1><h2 id="服务器连接失败" tabindex="-1">服务器连接失败？ <a class="header-anchor" href="#服务器连接失败" aria-label="Permalink to &quot;服务器连接失败？&quot;">​</a></h2><ul><li>检查网络连接是否正常</li><li>关闭网络代理工具（代理可能干扰 SSH 连接）</li></ul><h2 id="app-切到后台连接断开" tabindex="-1">APP 切到后台连接断开？ <a class="header-anchor" href="#app-切到后台连接断开" aria-label="Permalink to &quot;APP 切到后台连接断开？&quot;">​</a></h2><ul><li>Android：将应用的省电策略设置为 <code>无限制</code>，可以减少后台断连</li></ul><h2 id="为什么会出现资产数据消失" tabindex="-1">为什么会出现资产数据消失？ <a class="header-anchor" href="#为什么会出现资产数据消失" aria-label="Permalink to &quot;为什么会出现资产数据消失？&quot;">​</a></h2><p>常见原因有两类：</p><ul><li>数据隔离：不同账户使用独立的数据集，登出或切换账号后会看到不同的资产列表</li><li>应用卸载：卸载应用会同时删除本地数据</li></ul><h2 id="如何反馈问题" tabindex="-1">如何反馈问题？ <a class="header-anchor" href="#如何反馈问题" aria-label="Permalink to &quot;如何反馈问题？&quot;">​</a></h2><p>你可以通过以下方式联系 Chaterm：</p><ul><li>应用内反馈：<code>个人中心 &gt; 使用与反馈 &gt; 问题反馈</code></li><li>邮件支持：<code>support@chaterm.ai</code></li></ul><h2 id="支持哪些-ai-模型-如何切换" tabindex="-1">支持哪些 AI 模型？如何切换？ <a class="header-anchor" href="#支持哪些-ai-模型-如何切换" aria-label="Permalink to &quot;支持哪些 AI 模型？如何切换？&quot;">​</a></h2><p>登录后可在<a href="/docs/mobile/profile/#模型选择">个人中心 &gt; AI 设置 &gt; 模型选择</a>中查看并切换。目前支持 Kimi2.5、GLM-5 等主流厂商的旗舰模型，不同订阅类型拥有的模型不同，以实际为准。</p><h2 id="数据同步失败怎么办" tabindex="-1">数据同步失败怎么办？ <a class="header-anchor" href="#数据同步失败怎么办" aria-label="Permalink to &quot;数据同步失败怎么办？&quot;">​</a></h2><ul><li>确认已登录账号（未登录时同步不可用）</li><li>检查网络连接是否正常</li><li>在<a href="/docs/mobile/profile/#数据管理">个人中心 &gt; 数据管理</a>确认同步开关已开启</li><li>如问题持续，可尝试重新登录后再同步</li></ul><h2 id="未登录可以使用哪些功能" tabindex="-1">未登录可以使用哪些功能？ <a class="header-anchor" href="#未登录可以使用哪些功能" aria-label="Permalink to &quot;未登录可以使用哪些功能？&quot;">​</a></h2><p>未登录时可以添加和管理本地资产、建立 SSH 连接。AI 对话功能和数据云端同步需要登录后才能使用。</p><h2 id="排查建议" tabindex="-1">排查建议 <a class="header-anchor" href="#排查建议" aria-label="Permalink to &quot;排查建议&quot;">​</a></h2><p>如果问题与连接或登录相关，请先确认：</p><ul><li>应用版本是否为最新版</li><li>当前网络是否可访问目标主机</li><li>账号是否处于登录状态</li><li>模型和 AI 配置是否已正确设置</li></ul>',20),r=[t];function d(h,n,c,s,u,p){return i(),e("div",null,r)}const f=a(o,[["render",d]]);export{m as __pageData,f as default};
